class Ticket:
    def __init__(self, title):
        self.title = title

    def label(self):
        return self.title

from models.ticket import Ticket

class BugTicket(Ticket):
    def __init__(self, title, severity):
        super().__init__(title)
        self.severity = severity

    def label(self):
        return f"BUG: {self.title} ({self.severity})"

